const user = { address: { street: 'Main' } };

// Безопасный доступ к глубоким свойствам
const zip = user?.address?.zipcode;
// undefined, без ошибки TypeError

// С вызовом метода
const name = user?.getName?.();
// undefined, если метод не существует

// С массивом
const firstItem = arr?.[0];
// undefined, если arr равен null

// Комбинация с nullish coalescing
const city = user?.address?.city ?? 'Unknown';

const value = 0;
const empty = '';
const falseVal = false;

// || возвращает 'default' для ВСЕХ falsy значений
console.log(value || 'default');     // 'default' (неожиданно!)
console.log(empty || 'default');     // 'default' (неожиданно!)

// ?? работает только с null/undefined
console.log(value ?? 'default');     // 0 (корректно!)
console.log(empty ?? 'default');     // '' (корректно!)
console.log(falseVal ?? 'default');  // false (корректно!)
console.log(null ?? 'default');      // 'default'

