// ||= (Logical OR assignment)
let a = 0;
a ||= 10; // a === 10 (0 falsy)

let b = 5;
b ||= 10; // b === 5 (5 truthy, не меняется)

// ??= (Logical nullish assignment)
let c = null;
c ??= 'default'; // c === 'default'

let d = 0;
d ??= 'default'; // d === 0 (0 не nullish!)

// &&= (Logical AND assignment)
let e = 1;
e &&= 2; // e === 2 (1 truthy, присвоилось)

let f = 0;
f &&= 2; // f === 0 (0 falsy, не изменилось)

